    </details>

    <div class="battle-result-overlay" id="battle-result-overlay"><div class="result-panel"><h2 class="result-title" id="result-title">战斗结束</h2><p class="result-description" id="result-description">你获得了胜利！</p><textarea id="result-custom-message" class="result-custom-input" placeholder="可以在此输入额外信息 (例如战后总结、剧情对话等)"></textarea><button class="result-button" id="result-button">发送战斗结果</button></div></div>

    <script>
    document.addEventListener('DOMContentLoaded', () => {
        // [MODIFICATION] Storing TavernHelper in a variable for easier access and checking its existence.
        const TavernHelper = window.parent.TavernHelper;

        async function sendGameActionRequest(message) { try { if (window.SillyTavernAPI && window.SillyTavernAPI.sendMessage) { await window.SillyTavernAPI.sendMessage(message); return true; } if (window.extensionAPI && window.extensionAPI.sendMessage) { await window.extensionAPI.sendMessage(message); return true; } let textarea = null, sendButton = null; const textareaSelectors = ['#send_textarea', 'textarea[name="send_textarea"]', '#chat-input', 'textarea.chat-input', '#user-input', 'textarea#send_textarea', 'textarea']; const buttonSelectors = ['#send_but', 'button#send_but', 'input[type="submit"]', '.send_button', 'button[type="submit"]']; if (window.parent !== window) { for (const selector of textareaSelectors) try { textarea = window.parent.document.querySelector(selector); if (textarea) break; } catch (e) {} for (const selector of buttonSelectors) try { sendButton = window.parent.document.querySelector(selector); if (sendButton) break; } catch (e) {} } if (textarea && sendButton) { textarea.value = message; textarea.dispatchEvent(new Event('input', { bubbles: true })); sendButton.click(); return true; } if (window.parent !== window) { window.parent.postMessage({ type: 'send_message', message: message }, '*'); return true; } try { await navigator.clipboard.writeText(message); logSystemMessage("自动发送失败，消息已复制到剪贴板，请手动粘贴发送"); return false; } catch (clipboardError) { const tempTextarea = document.createElement('textarea'); tempTextarea.value = message; tempTextarea.style.cssText = 'position:fixed;top:50%;left:50%;transform:translate(-50%,-50%);z-index:10001;padding:10px;border:2px solid var(--pkmn-red);background-color:var(--pkmn-white);color:var(--pkmn-dark);width:80%;max-width:500px;height:100px; font-family: var(--font-pixel);'; document.body.appendChild(tempTextarea); tempTextarea.select(); logSystemMessage("自动发送失败，请手动复制上方文本框中的内容并发送"); setTimeout(() => document.body.removeChild(tempTextarea), 5000); return false; } } catch (error) { logSystemMessage(`发送失败: ${error.message}`); return false; } }

        const URL_BASES = { pokemon: 'https://play.pokemonshowdown.com/sprites/ani/', pokemonShiny: 'https://play.pokemonshowdown.com/sprites/ani-shiny/', items: 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/items/', attributes: 'https://raw.githubusercontent.com/msikma/pokesprite/master/misc/special-attribute/', types: 'https://raw.githubusercontent.com/msikma/pokesprite/master/misc/types/gen8/', categories: 'https://raw.githubusercontent.com/msikma/pokesprite/master/misc/seals/gen8/' };
        const TYPE_MAP = { '普通': 'normal', '火': 'fire', '水': 'water', '草': 'grass', '电': 'electric', '冰': 'ice', '格斗': 'fighting', '毒': 'poison', '地面': 'ground', '飞行': 'flying', '超能力': 'psychic', '虫': 'bug', '岩石': 'rock', '幽灵': 'ghost', '龙': 'dragon', '钢': 'steel', '妖精': 'fairy', '恶': 'dark' };
        const CATEGORY_MAP = { '物理': 'move-physical', '特殊': 'move-special', '变化': 'move-status' };
        const ATTRIBUTE_ICON_MAP = { 'mega': 'mega-evolution-sigil-hires.png', 'gmax': 'gigantamax-icon.png', 'alpha': 'alpha-icon.png', 'shiny': 'shiny-stars.png' };
        const STATUS_CLASS_MAP = { '中毒': 'status-psn', '麻痹': 'status-par', '睡眠': 'status-slp', '烧伤': 'status-brn', '冰冻': 'status-frz' };

        let gameState = {}; let isActionInProgress = false;
        let pendingActions = []; let actionSelectionStep = 0;
        let currentSelectionPhase = 'none';
        let tempActionPayload = {};
        let turnState = { armedMechanic: null, armedSpecialCommand: null };
        let forcedSwitchState = { isForced: false, slotIndex: -1 };
        let specialCommandUses = 0;
        const MAX_SPECIAL_COMMAND_USES = 3;

        // [MODIFICATION] New helper function to find the latest message with the battle UI.
        async function findLatestBattleMessageId() {
            if (!TavernHelper) return null;
            const lastMessageId = await TavernHelper.getLastMessageId();
            if (lastMessageId === null) return null;

            for (let i = lastMessageId; i >= 0; i--) {
                try {
                    const msg = (await TavernHelper.getChatMessages(i, { include_swipes: false }))[0];
                    if (msg && msg.message && msg.message.includes('[BATTLE_STATE_START]')) {
                        return i;
                    }
                } catch (error) {
                    // Ignore errors for messages that might not exist
                }
            }
            return null;
        }

        // [MODIFICATION] New function to persist the game state back to the chat message.
        async function persistGameState() {
            if (!TavernHelper) {
                logSystemMessage("错误: TavernHelper API不可用，无法保存进度。");
                return;
            }

            const battleMessageId = await findLatestBattleMessageId();
            if (battleMessageId === null) {
                logSystemMessage("严重错误: 找不到战斗UI所在的消息，无法保存进度！");
                return;
            }

            try {
                const currentGameStateString = JSON.stringify(gameState, null, 2);
                const newStateBlock = `[BATTLE_STATE_START]${currentGameStateString}[BATTLE_STATE_END]`;

                const existingMessage = (await TavernHelper.getChatMessages(battleMessageId, { include_swipes: false }))[0];
                if (!existingMessage) {
                     logSystemMessage("严重错误: 无法读取战斗消息，无法保存进度！");
                     return;
                }

                const regex = /\[BATTLE_STATE_START\][\s\S]*?\[BATTLE_STATE_END\]/s;
                const newContent = existingMessage.message.replace(regex, newStateBlock);

                await TavernHelper.setChatMessages([
                    { message_id: battleMessageId, message: newContent }
                ], { refresh: 'none' });

                console.log(`[Pokemon Battle] Game state successfully persisted to message ID: ${battleMessageId}`);
            } catch (error) {
                console.error("[Pokemon Battle] Failed to persist game state:", error);
                logSystemMessage("错误: 保存战斗进度失败。详情请查看控制台。");
            }
        }

        function updateGameState(newState) {
            if (newState.playerPokemon && !newState.playerActive) newState.playerActive = [newState.playerPokemon]; 
            if (newState.opponentPokemon && !newState.opponentActive) newState.opponentActive = [newState.opponentPokemon]; 
            if (!newState.usedMechanics) newState.usedMechanics = { mega: false, zMove: false, dynamax: false, tera: false }; 
            if (gameState.opponentTrainer !== newState.opponentTrainer) {
                specialCommandUses = 0;
            }
            gameState = newState; 
            renderAll();
        }

        async function animateAndApplyStateUpdate(newGameState) {
            const animationPromises = [];

            const processSide = (side, oldActive, newActive) => {
                (newActive || []).forEach((newPkmn, i) => {
                    const oldPkmn = (oldActive || [])[i];
                    if (!oldPkmn || !newPkmn || oldPkmn.currentHp === newPkmn.currentHp) return;
                    const box = document.getElementById(`${side}-slot-${i}`);
                    if (!box) return;
                    const hpBar = box.querySelector('.hp-bar');
                    const promise = new Promise(resolve => {
                        hpBar.addEventListener('transitionend', resolve, { once: true });
                        setTimeout(resolve, 900);
                    });
                    animationPromises.push(promise);
                    const newHpPercent = (newPkmn.currentHp / newPkmn.maxHp) * 100;
                    const newHpColorClass = newHpPercent > 50 ? 'hp-green' : newHpPercent > 20 ? 'hp-yellow' : 'hp-red';
                    hpBar.className = 'hp-bar ' + newHpColorClass;
                    hpBar.style.width = newHpPercent + '%';
                });
            };
            processSide('player', gameState.playerActive, newGameState.playerActive);
            processSide('opponent', gameState.opponentActive, newGameState.opponentActive);

            if (animationPromises.length > 0) {
                await Promise.all(animationPromises);
            }

            updateGameState(newGameState);

            // [MODIFICATION] Persist the state after updating it.
            await persistGameState();

            isActionInProgress = false;
            toggleControls(true);
            const playerInputRequired = checkForcedAction();
            if (!playerInputRequired) {
                showMainMenu();
            }
        }

        function checkForcedAction() {
            if (gameState.battleResult && gameState.battleResult.status) {
                showResultScreen(gameState.battleResult);
                return true;
            }
            if (gameState.forceSwitchRequest) {
                document.getElementById('pending-actions-panel').style.display = 'none';
                document.getElementById('pokemon-details-panel').style.display = 'none';
                document.getElementById('main-controls').style.display = 'none';
                const submenu = document.getElementById('submenu-controls');
                submenu.innerHTML = '';
                submenu.style.display = 'flex';
                submenu.classList.add('active');

                const { slotIndex, reason } = gameState.forceSwitchRequest;
                const pkmnName = gameState.playerActive[slotIndex]?.name || `位置 ${slotIndex + 1} 的宝可梦`;
                logSystemMessage(reason || `${pkmnName}需要被换下！`);
                forcedSwitchState = { isForced: true, slotIndex: slotIndex };
                showPartyListForSwitch(true, slotIndex);
                gameState.forceSwitchRequest = null; 
                return true;
            }
            return hasFaintedPokemonRequiringSwitch();
        }

        function hasFaintedPokemonRequiringSwitch() {
             const faintedPlayerSlots = (gameState.playerActive || []).map((p, i) => (p && p.currentHp <= 0) ? i : -1).filter(i => i !== -1);
            if (faintedPlayerSlots.length > 0) {
                return gameState.party.some(p => { 
                    if (!p) return false; 
                    const isEgg = p.name && (p.name.toLowerCase().includes('egg') || p.name === '蛋'); 
                    const isActive = (gameState.playerActive || []).some(ap => ap && ap.name === p.name); 
                    return p.currentHp > 0 && !isEgg && !isActive; 
                });
            }
            return false;
        }

        function showResultScreen(result) { 
            const overlay = document.getElementById('battle-result-overlay'); 
            const titleEl = document.getElementById('result-title'); 
            const descEl = document.getElementById('result-description'); 
            const buttonEl = document.getElementById('result-button'); 
            if (!overlay || !titleEl || !descEl || !buttonEl) return; 
            titleEl.textContent = result.status; 
            descEl.textContent = result.description || '战斗已分出胜负。'; 

            const newButton = buttonEl.cloneNode(true); 
            buttonEl.parentNode.replaceChild(newButton, buttonEl); 

            newButton.addEventListener('click', async () => { 
                newButton.disabled = true;
                newButton.textContent = '发送中...';

                let messageToSend = ''; 
                const opponentName = gameState.opponentTrainer === '野生' ? `野生的宝可梦` : gameState.opponentTrainer; 

                if (result.status === '捕捉成功') { 
                    const capturedName = gameState.opponentActive && gameState.opponentActive.length > 0 ? gameState.opponentActive[0].name : '宝可梦'; 
                    messageToSend = `成功捕捉 ${capturedName}！`; 
                } else { 
                    messageToSend = `和${opponentName}的战斗结果：${result.status}。`; 
                } 

                messageToSend += '\n\n--- 队伍状态和经验总结 ---';
                const expGained = result.experienceGained; 

                (gameState.party || []).forEach((pkmn, index) => {
                    if (!pkmn) return;
                    let pkmnLine = `\n${index + 1}. ${pkmn.name} (Lv.${pkmn.level}) - HP: ${pkmn.currentHp}/${pkmn.maxHp} - 状态: ${pkmn.status || '健康'}`;
                    if (expGained && expGained[index] !== undefined && expGained[index] !== null) {
                        pkmnLine += ` | 获得经验: ${expGained[index]}`;
                    }
                    messageToSend += pkmnLine;
                });

                const customMessageInput = document.getElementById('result-custom-message');
                const customMessage = customMessageInput ? customMessageInput.value.trim() : '';
                if (customMessage) {
                    messageToSend += `\n\n--- 额外记录 ---\n${customMessage}`;
                }

                logSystemMessage(`正在发送战斗结果...`); 
                const success = await sendGameActionRequest(messageToSend);

                if (success) {
                    newButton.textContent = '发送成功 ✓';
                    setTimeout(() => { 
                        overlay.classList.remove('visible'); 
                    }, 1500); 
                } else {
                    newButton.textContent = '自动发送失败';
                    setTimeout(() => {
                        newButton.textContent = '发送战斗结果';
                        newButton.disabled = false; 
                    }, 3000);
                }
            }); 

            overlay.classList.add('visible'); 
            toggleControls(false); 
        }

        function initializeBattle(initialState) { if (!initialState || typeof initialState !== 'object') { document.body.innerHTML = '...'; return; } console.log("Battle UI Initializing with state:", initialState); updateGameState(initialState); bindEventListeners(); if (!checkForcedAction()) { showMainMenu(); } }
