    async function sendGameActionRequest(message) { try { if (window.SillyTavernAPI && window.SillyTavernAPI.sendMessage) { await window.SillyTavernAPI.sendMessage(message); return true; } if (window.extensionAPI && window.extensionAPI.sendMessage) { await window.extensionAPI.sendMessage(message); return true; } let textarea = null, sendButton = null; const textareaSelectors = ['#send_textarea', 'textarea[name="send_textarea"]', '#chat-input', 'textarea.chat-input', '#user-input', 'textarea#send_textarea', 'textarea']; const buttonSelectors = ['#send_but', 'button#send_but', 'input[type="submit"]', '.send_button', 'button[type="submit"]']; if (window.parent !== window) { for (const selector of textareaSelectors) try { textarea = window.parent.document.querySelector(selector); if (textarea) break; } catch (e) {} for (const selector of buttonSelectors) try { sendButton = window.parent.document.querySelector(selector); if (sendButton) break; } catch (e) {} } if (textarea && sendButton) { textarea.value = message; textarea.dispatchEvent(new Event('input', { bubbles: true })); sendButton.click(); return true; } if (window.parent !== window) { window.parent.postMessage({ type: 'send_message', message: message }, '*'); return true; } try { await navigator.clipboard.writeText(message); showError("自动发送失败，消息已复制到剪贴板，请手动粘贴发送"); return false; } catch (clipboardError) { const tempTextarea = document.createElement('textarea'); tempTextarea.value = message; tempTextarea.style.cssText = 'position:fixed;top:50%;left:50%;transform:translate(-50%,-50%);z-index:10000;padding:10px;border:2px solid var(--day-hp-low);background-color:var(--day-window-bg);color:var(--day-text-primary);width:80%;max-width:500px;height:100px; font-family: var(--font-pixel);'; document.body.appendChild(tempTextarea); tempTextarea.select(); showError("自动发送失败，请手动复制上方文本框中的内容并发送"); setTimeout(() => document.body.removeChild(tempTextarea), 5000); return false; } } catch (error) { showError(`发送失败: ${error.message}`); return false; } }

    const dataSource = document.querySelector('.statusbar-data-source');
    if (!dataSource || !dataSource.textContent.trim()) return;

    function parseSource(text) { const data = {}; const blockRegex = /\[([^\]]+)\]([\s\S]*?)\[\/\1\]/g; let match; while ((match = blockRegex.exec(text)) !== null) { const blockName = match[1]; const blockContent = match[2].trim(); const items = {}; blockContent.split('\n').forEach(line => { const parts = line.split(':'); if (parts.length >= 2) { const key = parts[0].trim(); const value = parts.slice(1).join(':').trim(); items[key] = value; } }); data[blockName] = items; } return data; }
    const rawData = parseSource(dataSource.textContent);

    function structureData(parsed) {
        const structured = { team: [], bag: {}, boxes: {}, trainer: {}, relationships: {} };
        structured.trainer = { name: parsed['训练家信息']?.['名字'] || '无名氏', money: parsed['训练家信息']?.['金钱'] || '0', badges: parsed['训练家信息']?.['徽章'] || '0', commandLevel: parsed['训练家信息']?.['可命令等级'] || '0', renown: parsed['训练家信息']?.['声望'] || 'N/A' };
        const teamData = parsed['队伍状态'] || {};
        for (let i = 1; i <= 6; i++) { if (teamData[`队伍${i}_名字`] && teamData[`队伍${i}_名字`] !== '空') { structured.team.push({ name: teamData[`队伍${i}_名字`], level: teamData[`队伍${i}_等级`], hp: teamData[`队伍${i}_HP`], exp: teamData[`队伍${i}_经验`], moves: teamData[`队伍${i}_技能`], type1: teamData[`队伍${i}_属性1`], type2: teamData[`队伍${i}_属性2`], icon: teamData[`队伍${i}_图标`], isShiny: teamData[`队伍${i}_是否闪光`] === '是', hatchTime: teamData[`队伍${i}_孵化剩余`], nature: teamData[`队伍${i}_性格`], ability: teamData[`队伍${i}_特性`], heldItem: teamData[`队伍${i}_携带道具`], friendship: teamData[`队伍${i}_亲密度`], gender: teamData[`队伍${i}_性别`] }); } }
        for (const key in parsed) { if (key.startsWith('背包_')) structured.bag[key.replace('背包_', '')] = parsed[key]; }
