        for (const key in boxData) { const match = key.match(/盒子(\d+)_宝可梦(\d+)_(.+)/); if (match) { const [, boxNum, pkmnNum, prop] = match; if (!structured.boxes[boxNum]) structured.boxes[boxNum] = {}; if (!structured.boxes[boxNum][pkmnNum]) structured.boxes[boxNum][pkmnNum] = {}; structured.boxes[boxNum][pkmnNum][prop] = boxData[key]; } }
