<body>
<div class="statusbar-data-source">$1</div>
<div id="pm-hud-container" class="pm-hud-container">
  <div class="hud-top-bar"><span id="theme-toggle"></span></div>
  <div id="hud-trainer" class="pm-hud-window"><div class="pm-hud-header"><span>训练家信息</span><span class="collapse-toggle">▼</span></div><div id="trainer-content" class="pm-hud-content"><div class="trainer-info-grid"><div class="trainer-info-item"><span>名字</span><span id="trainer-name"></span></div><div class="trainer-info-item"><span>金钱</span><span id="trainer-money"></span></div><div class="trainer-info-item"><span>徽章</span><span id="trainer-badges"></span></div><div class="trainer-info-item"><span>指令等级</span><span id="trainer-command-level"></span></div><div class="trainer-info-item"><span>声望</span><span id="trainer-renown"></span></div></div></div></div>
  <div id="hud-team" class="pm-hud-window"><div class="pm-hud-header"><span>当前队伍</span><span class="collapse-toggle">▼</span></div><div id="team-content" class="pm-hud-content"></div></div>
  <!-- 新增附近宝可梦栏 -->
  <div id="hud-nearby" class="pm-hud-window"><div class="pm-hud-header"><span>附近宝可梦</span><span class="collapse-toggle">▼</span></div><div id="nearby-content" class="pm-hud-content"></div></div>
  <div id="hud-rotom-phone" class="pm-hud-window"><div class="pm-hud-header"><span>洛托姆手机</span><span class="collapse-toggle">▼</span></div><div class="pm-hud-content"><button id="call-rotom-btn" class="rotom-action-button">呼出手机</button></div></div>
  <div id="hud-bag" class="pm-hud-window"><div class="pm-hud-header"><span>背包</span><span class="collapse-toggle">▼</span></div><div id="bag-content" class="pm-hud-content"></div></div>
  <div id="hud-box" class="pm-hud-window"><div class="pm-hud-header"><span>宝可梦盒子</span><span class="collapse-toggle">▼</span></div><div id="box-content" class="pm-hud-content"></div></div>
  <div id="hud-relationships" class="pm-hud-window"><div class="pm-hud-header"><span>人际关系</span><span class="collapse-toggle">▼</span></div><div id="relationships-content" class="pm-hud-content"></div></div>
</div>
<!-- 弹窗结构 -->
<div id="pm-modal-overlay" class="pm-modal-overlay hidden">
    <div id="pm-modal-content" class="pm-modal-content"></div>
</div>
<script>
document.addEventListener('DOMContentLoaded', () => {
    // --- 数据与元素定义 ---
    const STATUS_ICONS = {
        '闪光': 'https://raw.githubusercontent.com/msikma/pokesprite/master/misc/special-attribute/shiny-stars.png',
        '头目': 'https://raw.githubusercontent.com/msikma/pokesprite/master/misc/special-attribute/alpha-icon.png',
        '霸主': 'https://raw.githubusercontent.com/msikma/pokesprite/master/misc/special-attribute/alpha-icon.png', // 使用相同图标
        '极巨化': 'https://raw.githubusercontent.com/msikma/pokesprite/master/misc/special-attribute/gigantamax-icon.png',
        '太晶化': 'https://raw.githubusercontent.com/sora-64/DS-Pokemon-Editor/main/Resources/terastal.png' // 找一个合适的太晶图标
    };
    const dataSource = document.querySelector('.statusbar-data-source');
    const container = document.getElementById('pm-hud-container');
    const teamContent = document.getElementById('team-content');
    const bagContent = document.getElementById('bag-content');
    const boxContent = document.getElementById('box-content');
    const relationshipsContent = document.getElementById('relationships-content');
    const nearbyContent = document.getElementById('nearby-content');
    const modalOverlay = document.getElementById('pm-modal-overlay');
    const modalContent = document.getElementById('pm-modal-content');
    if (!dataSource || !dataSource.textContent.trim()) return;

    // --- 核心功能函数 ---
    function showError(message) { /* ... (函数体无变化) ... */ console.error(`Status Bar Action Error: ${message}`); const errorEl = document.createElement('div'); errorEl.textContent = message; errorEl.style.cssText = `background-color: var(--day-hp-low); color: white; padding: 8px; margin: 0 0 10px 0; border-radius: 4px; text-align: center; font-size: 0.9rem;`; const hudContainer = document.getElementById('pm-hud-container'); if (hudContainer) { hudContainer.insertBefore(errorEl, hudContainer.firstChild.nextSibling); setTimeout(() => { if(errorEl.parentElement) errorEl.parentElement.removeChild(errorEl); }, 4000); } }
    async function sendGameActionRequest(message) { /* ... (函数体无变化) ... */ try { if (window.SillyTavernAPI && window.SillyTavernAPI.sendMessage) { await window.SillyTavernAPI.sendMessage(message); return true; } if (window.extensionAPI && window.extensionAPI.sendMessage) { await window.extensionAPI.sendMessage(message); return true; } let textarea = null, sendButton = null; const textareaSelectors = ['#send_textarea', 'textarea[name="send_textarea"]', '#chat-input', 'textarea.chat-input', '#user-input', 'textarea#send_textarea', 'textarea']; const buttonSelectors = ['#send_but', 'button#send_but', 'input[type="submit"]', '.send_button', 'button[type="submit"]']; if (window.parent !== window) { for (const selector of textareaSelectors) try { textarea = window.parent.document.querySelector(selector); if (textarea) break; } catch (e) {} for (const selector of buttonSelectors) try { sendButton = window.parent.document.querySelector(selector); if (sendButton) break; } catch (e) {} } if (textarea && sendButton) { textarea.value = message; textarea.dispatchEvent(new Event('input', { bubbles: true })); sendButton.click(); return true; } if (window.parent !== window) { window.parent.postMessage({ type: 'send_message', message: message }, '*'); return true; } try { await navigator.clipboard.writeText(message); showError("自动发送失败，消息已复制到剪贴板，请手动粘贴发送"); return false; } catch (clipboardError) { const tempTextarea = document.createElement('textarea'); tempTextarea.value = message; tempTextarea.style.cssText = 'position:fixed;top:50%;left:50%;transform:translate(-50%,-50%);z-index:10000;padding:10px;border:2px solid var(--day-hp-low);background-color:var(--day-window-bg);color:var(--day-text-primary);width:80%;max-width:500px;height:100px; font-family: var(--font-pixel);'; document.body.appendChild(tempTextarea); tempTextarea.select(); showError("自动发送失败，请手动复制上方文本框中的内容并发送"); setTimeout(() => document.body.removeChild(tempTextarea), 5000); return false; } } catch (error) { showError(`发送失败: ${error.message}`); return false; } }
    function parseSource(text) { /* ... (函数体无变化) ... */ const data = {}; const blockRegex = /\[([^\]]+)\]([\s\S]*?)\[\/\1\]/g; let match; while ((match = blockRegex.exec(text)) !== null) { const blockName = match[1]; const blockContent = match[2].trim(); const items = {}; blockContent.split('\n').forEach(line => { const parts = line.split(':'); if (parts.length >= 2) { const key = parts[0].trim(); const value = parts.slice(1).join(':').trim(); items[key] = value; } }); data[blockName] = items; } return data; }

    function structureData(parsed) {
        const structured = { team: [], bag: {}, boxes: {}, trainer: {}, relationships: {}, nearby: [] };
        // 训练家 & 队伍 & 背包 & 盒子 & 人际关系 (逻辑无变化)
        structured.trainer = { name: parsed['训练家信息']?.['名字'] || '无名氏', money: parsed['训练家信息']?.['金钱'] || '0', badges: parsed['训练家信息']?.['徽章'] || '0', commandLevel: parsed['训练家信息']?.['可命令等级'] || '0', renown: parsed['训练家信息']?.['声望'] || 'N/A' };
        const teamData = parsed['队伍状态'] || {}; for (let i = 1; i <= 6; i++) { if (teamData[`队伍${i}_名字`] && teamData[`队伍${i}_名字`] !== '空') { structured.team.push({ name: teamData[`队伍${i}_名字`], level: teamData[`队伍${i}_等级`], hp: teamData[`队伍${i}_HP`], exp: teamData[`队伍${i}_经验`], moves: teamData[`队伍${i}_技能`], type1: teamData[`队伍${i}_属性1`], type2: teamData[`队伍${i}_属性2`], icon: teamData[`队伍${i}_图标`], isShiny: teamData[`队伍${i}_是否闪光`] === '是', hatchTime: teamData[`队伍${i}_孵化剩余`], nature: teamData[`队伍${i}_性格`], ability: teamData[`队伍${i}_特性`], heldItem: teamData[`队伍${i}_携带道具`], friendship: teamData[`队伍${i}_亲密度`], gender: teamData[`队伍${i}_性别`] }); } }
        for (const key in parsed) { if (key.startsWith('背包_')) structured.bag[key.replace('背包_', '')] = parsed[key]; }
        const boxData = parsed['宝可梦盒子'] || {}; for (const key in boxData) { const match = key.match(/盒子(\d+)_宝可梦(\d+)_(.+)/); if (match) { const [, boxNum, pkmnNum, prop] = match; if (!structured.boxes[boxNum]) structured.boxes[boxNum] = {}; if (!structured.boxes[boxNum][pkmnNum]) structured.boxes[boxNum][pkmnNum] = {}; structured.boxes[boxNum][pkmnNum][prop] = boxData[key]; } }
        structured.relationships = parsed['人际关系'] || {};
        // 新增：解析附近宝可梦
        const nearbyData = parsed['附近宝可梦'] || {};
        const nearbyPkmn = {};
        for (const key in nearbyData) {
            const match = key.match(/附近(\d+)_(.+)/);
            if (match) {
                const [, index, prop] = match;
                if (!nearbyPkmn[index]) nearbyPkmn[index] = {};
                nearbyPkmn[index][prop] = nearbyData[key];
            }
        }
        structured.nearby = Object.values(nearbyPkmn);
        structured.config = parsed['config'] || { theme: 'day' };
        return structured;
    }

    // --- 弹窗管理 ---
    function openModal(htmlContent) { modalContent.innerHTML = htmlContent; modalOverlay.classList.remove('hidden'); }
    function closeModal() { modalOverlay.classList.add('hidden'); modalContent.innerHTML = ''; }
    modalOverlay.addEventListener('click', (e) => { if (e.target === modalOverlay) closeModal(); });

    const rawData = parseSource(dataSource.textContent);
    const data = structureData(rawData);

    // --- UI 渲染 ---
    function renderTrainerInfo() { /* ... (渲染训练家信息，无变化) ... */ document.getElementById('trainer-name').textContent = data.trainer.name; document.getElementById('trainer-money').textContent = '₽' + data.trainer.money; document.getElementById('trainer-badges').textContent = data.trainer.badges; document.getElementById('trainer-command-level').textContent = data.trainer.commandLevel; document.getElementById('trainer-renown').textContent = data.trainer.renown; }
    function renderTeam() { /* ... (渲染队伍，无变化) ... */ teamContent.innerHTML = data.team.length > 0 ? data.team.map(p => { if (p.name === '蛋') { const iconUrl = 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/items/mystery-egg.png'; const iconStyle = `style="background-image: url('${iconUrl}');"`; const hatchInfo = p.hatchTime ? `剩余孵化时间：${p.hatchTime}` : '即将孵化...'; return `<div class="pokemon-entry"><div class="pokemon-icon" ${iconStyle}></div><div class="pokemon-info"><div class="pokemon-name-level"><span>蛋</span></div><div class="egg-hatching-info"><div>正在孵化中。。。</div><div>${hatchInfo}</div></div></div></div>`; } else { const [currentHP, maxHP] = (p.hp || '0/0').split('/').map(Number); const hpPercent = maxHP > 0 ? (currentHP / maxHP) * 100 : 0; let hpClass = hpPercent < 20 ? 'hp-low' : hpPercent < 50 ? 'hp-mid' : 'hp-high'; const [currentEXP, totalEXP] = (p.exp || '0/100').split('/').map(Number); const expPercent = totalEXP > 0 ? (currentEXP / totalEXP) * 100 : 0; let genderHTML = ''; if (p.gender === '♂') genderHTML = ` <span class="gender-male">♂</span>`; else if (p.gender === '♀') genderHTML = ` <span class="gender-female">♀</span>`; let typesHTML = (p.type1 && p.type1 !== '无' ? `<span class="type-badge" style="background-color: var(--type-${p.type1});">${p.type1}</span>` : '') + (p.type2 && p.type2 !== '无' ? `<span class="type-badge" style="background-color: var(--type-${p.type2});">${p.type2}</span>` : ''); let movesHTML = p.moves ? `<div class="pokemon-moves"><strong>技能:</strong> ${p.moves.replace(/,/g, ' / ')}</div>` : ''; let detailsHTML = [(p.nature ? `<div><strong>性格:</strong> <span>${p.nature}</span></div>` : ''), (p.ability ? `<div><strong>特性:</strong> <span>${p.ability}</span></div>` : ''), (p.heldItem && p.heldItem !== '无' ? `<div><strong>道具:</strong> <span>${p.heldItem}</span></div>` : ''), (p.friendship ? `<div><strong>亲密:</strong> <span>${p.friendship}</span></div>` : '')].filter(Boolean).join(''); if(detailsHTML) { detailsHTML = `<div class="pokemon-details">${detailsHTML}</div>`; } let iconStyle = ''; if (p.icon) { const baseUrl = p.isShiny ? 'https://play.pokemonshowdown.com/sprites/ani-shiny/' : 'https://play.pokemonshowdown.com/sprites/ani/'; const iconUrl = baseUrl + p.icon; iconStyle = `style="background-image: url('${iconUrl}');"`; } return `<div class="pokemon-entry"><div class="pokemon-icon" ${iconStyle}></div><div class="pokemon-info"><div class="pokemon-name-level"><span>${p.name}${genderHTML}</span><span>Lv.${p.level}</span></div><div class="hp-bar-bg"><div class="hp-bar-fg ${hpClass}" style="width: ${hpPercent}%;"></div></div><div class="exp-bar-bg"><div class="exp-bar-fg" style="width: ${expPercent}%;"></div></div><div class="pokemon-types">${typesHTML}</div>${movesHTML}${detailsHTML}</div></div>`; } }).join('') : '<div>队伍中没有宝可梦。</div>'; }
    function renderBag() { /* ... (渲染背包，无变化) ... */ const bagHTML = Object.entries(data.bag).map(([cat, items]) => { if (Object.keys(items).length === 0) return ''; return `<div class="bag-category"><div class="bag-category-title">${cat}</div><ul class="bag-item-list">${Object.entries(items).map(([name, value]) => { const parts = String(value).split(','); const count = parts[0].trim(); const iconFile = parts.length > 1 ? parts[1].trim() : null; let iconHTML = '<div class="item-icon"></div>'; if (iconFile) { const iconUrl = `https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/items/${iconFile}`; iconHTML = `<div class="item-icon" style="background-image: url('${iconUrl}')"></div>`; } return `<li class="bag-item"><div class="item-info">${iconHTML}<span>${name}</span></div><span>x${count}</span></li>`; }).join('')}</ul></div>`; }).join(''); bagContent.innerHTML = bagHTML.trim() ? bagHTML : '<div>背包是空的。</div>'; }
