            const count = String(value).split(',')[0].trim();
            return `<button class="rotom-action-button" data-ball-name="${name}">${name} (x${count})</button>`;
        }).join('');
        if (!buttonsHTML) buttonsHTML = '<div>背包里没有精灵球。</div>';

        let modalHTML = `<div class="pm-modal-header">选择精灵球</div><div class="modal-list">${buttonsHTML}</div><button class="pm-modal-close" onclick="this.parentElement.parentElement.classList.add('hidden')">×</button>`;
        openModal(modalHTML);

        document.querySelectorAll('[data-ball-name]').forEach(button => {
            button.addEventListener('click', async (e) => {
                const ballName = e.currentTarget.dataset.ballName;
                await sendGameActionRequest(`向 ${pkmn.名字} 使用了 ${ballName}`);
                closeModal();
            });
        });
    }

    function showTeamSelectModal(pkmn) {
        const team = data.team.filter(p => p.name !== '蛋' && (p.hp || '0/0').split('/')[0] > 0);
        let buttonsHTML = team.map(member => {
            return `<button class="rotom-action-button" data-member-name="${member.name}">上吧！${member.name} (Lv.${member.level})</button>`;
        }).join('');
        if (!buttonsHTML) buttonsHTML = '<div>队伍中没有可以战斗的宝可梦。</div>';

        const raidType = pkmn.状态 === '极巨化' ? '极巨团体战' : '太晶团体战';
        let modalHTML = `<div class="pm-modal-header">选择上场的宝可梦</div><div class="modal-list">${buttonsHTML}</div><button class="pm-modal-close" onclick="this.parentElement.parentElement.classList.add('hidden')">×</button>`;
        openModal(modalHTML);

        document.querySelectorAll('[data-member-name]').forEach(button => {
