    // --- 初始化与事件绑定 ---
    function applyTheme(theme) { container.className = 'pm-hud-container'; container.classList.add(theme === 'night' ? 'theme-night' : 'theme-day'); const themeToggle = document.getElementById('theme-toggle'); if (themeToggle) { themeToggle.textContent = theme === 'night' ? '☀️' : '🌙'; } try { localStorage.setItem('pmHudTheme', theme); } catch (e) {} }
    let initialTheme = 'day'; try { initialTheme = localStorage.getItem('pmHudTheme') || data.config.theme || 'day'; } catch (e) { initialTheme = data.config.theme || 'day'; }
    applyTheme(initialTheme);

    document.getElementById('theme-toggle').addEventListener('click', (e) => { e.stopPropagation(); const newTheme = container.classList.contains('theme-night') ? 'day' : 'night'; applyTheme(newTheme); });

    ['hud-trainer', 'hud-team', 'hud-rotom-phone', 'hud-bag', 'hud-box', 'hud-relationships', 'hud-nearby'].forEach(id => { const w = document.getElementById(id); if (w) { const h = w.querySelector('.pm-hud-header'); try { if (localStorage.getItem(id + '-collapsed') === 'true') w.classList.add('collapsed'); } catch (e) {} if (h) h.addEventListener('click', (e) => { if (e.target.closest('#theme-toggle')) return; const i = w.classList.toggle('collapsed'); try { localStorage.setItem(id + '-collapsed', i); } catch (e) {} }); } });

    const callRotomBtn = document.getElementById('call-rotom-btn');
    if (callRotomBtn) {
        callRotomBtn.addEventListener('click', async () => {
            callRotomBtn.disabled = true; callRotomBtn.textContent = '呼叫中...';
            const success = await sendGameActionRequest('呼出 洛托姆手机');
            if (success) { callRotomBtn.textContent = '呼叫成功 ✓'; } else { callRotomBtn.textContent = '自动发送失败'; }
            setTimeout(() => { callRotomBtn.textContent = '呼出手机'; callRotomBtn.disabled = false; }, 2500);
        });
    }

    renderTrainerInfo();
    renderTeam();
    renderBag();
    renderBox();
    renderRelationships();
    renderNearby();
});
</script>
</body>
