    function renderMainPage(data) { const page = document.createElement('div'); page.id = 'page-main'; page.className = 'rotom-page active'; const trainer = data.trainer_info || {}; const tasks = data.tasks || {}; page.innerHTML = `<div class="main-grid"><div class="info-block"><h3>Thông tin Huấn luyện viên</h3><div class="info-item"><span>Tên:</span><span>${trainer.name || 'N/A'}</span></div><div class="info-item"><span>Tiền:</span><span>₽${trainer.money || 0}</span></div><div class="info-item"><span>Huy hiệu:</span><span>${trainer.badges || 0}</span></div><div class="info-item"><span>Cấp độ lệnh:</span><span>${trainer.command_level || 0}</span></div><div class="info-item"><span>Danh tiếng:</span><span>${trainer.renown || 'N/A'}</span></div><div class="info-item"><span>Danh hiệu:</span><span>${trainer.current_title || 'Không'}</span></div></div><div class="info-block"><h3>Kỷ lục Phiêu lưu</h3><div class="info-item"><span>Pokédex:</span><span>${trainer.pokedex_caught || 0}/${trainer.pokedex_seen || 0}</span></div><div class="info-item"><span>Shiny:</span><span>${trainer.shiny_caught || 0}/${trainer.shiny_seen || 0}</span></div><div class="info-item"><span>Huyền thoại:</span><span>${trainer.legend_caught || 0}/${trainer.legend_seen || 0}</span></div><div class="info-item"><span>Điểm Khai phá:</span><span>${trainer.pioneer_points || 0}</span></div><div class="info-item"><span>Điểm Thành tựu:</span><span>${trainer.achievement_points || 0}</span></div></div><div class="task-block" style="grid-column: 1 / -1;"><h3>Theo dõi Nhiệm vụ</h3><div class="task-item"><span>Hành trình Sử thi:</span><span>${tasks.main || 'Không'}</span></div><div class="task-item"><span>Nhiệm vụ Huyền thoại:</span><span>${tasks.legend || 'Không'}</span></div><div class="task-item"><span>Truy nã Hàng ngày:</span><span>${tasks.daily_1 !== 'Không' ? tasks.daily_1 : (tasks.daily_2 !== 'Không' ? tasks.daily_2 : 'Không')}</span></div><div class="task-item"><span>Yêu cầu Lạ:</span><span>${tasks.random_1 !== 'Không' ? tasks.random_1 : 'Không'}</span></div></div></div><div class="main-actions"><button class="rotom-button" data-page="page-nearby">Pokémon Gần đây</button><button class="rotom-button" data-page="page-box">Hộp Pokémon</button><button class="rotom-button" data-page="page-team">Đội hình Hiện tại</button><button class="rotom-button" data-page="page-shop">Sàn giao dịch</button><button class="rotom-button" data-page="page-titles">Danh hiệu Sở hữu</button><button class="rotom-button" data-page="page-bag">Ba lô</button><button class="rotom-button" data-page="page-achievements">Thành tựu Mở khóa</button><button class="rotom-button" data-page="page-breeding">Hộp Phối giống</button><button class="rotom-button" data-page="page-relationships">Mối quan hệ</button><button class="rotom-button" data-page="page-events">Sự kiện Lớn</button></div>`; screen.appendChild(page); page.querySelectorAll('.rotom-button[data-page]').forEach(btn => { btn.onclick = () => showPage(btn.dataset.page); }); }
    function renderGenericListPage(id, title, items, itemRenderer) { const page = document.createElement('div'); page.id = id; page.className = 'rotom-page'; const pageTitle = document.createElement('div'); pageTitle.className = 'page-title'; pageTitle.innerHTML = title; page.appendChild(pageTitle); const list = document.createElement('ul'); list.className = 'generic-list'; if (items && Object.keys(items).length > 0) { Object.values(items).forEach(item => { if(item.name && item.name !== 'Không' && item.name !== '无') list.appendChild(itemRenderer(item)); }); } if (list.children.length === 0) { list.innerHTML = `<li class="generic-list-item">Trống rỗng...</li>`; } page.appendChild(list); page.appendChild(createBackButton('page-main')); screen.appendChild(page); }
    function renderEventsPage(eventsData) { const page = document.createElement('div'); page.id = 'page-events'; page.className = 'rotom-page'; const events = eventsData || {}; page.innerHTML = `<div class="page-title">Sự kiện Lớn Hiện tại</div><div class="task-block"><h3>Gặp gỡ Đặc biệt lân cận</h3><p>${events.local_encounter || 'Sóng yên biển lặng, không có động tĩnh đặc biệt.'}</p></div><div class="task-block"><h3>Tin tức Khu vực</h3><p>${events.regional_news || 'Khu vực tạm thời không có tin tức quan trọng.'}</p></div><div class="task-block"><h3>Động thái Vùng miền</h3><p>${events.area_news || 'Khu vực hiện tại yên bình.'}</p></div>`; page.appendChild(createBackButton('page-main')); screen.appendChild(page); }

    function renderPokemonDetailsPage(pokemonKey, pokemon) {
        const uniqueId = `page-details-${pokemonKey}`;
        if(document.getElementById(uniqueId)) { showPage(uniqueId); return; }

        const [currentEXP, totalEXP] = (pokemon.exp || '0/100').split('/').map(Number);
        const expPercent = totalEXP > 0 ? (currentEXP / totalEXP) * 100 : 0;
        const displayName = (pokemon.nickname && pokemon.nickname !== 'Không') ? pokemon.nickname : pokemon.name;
        let titlePrefix = '';
        if (pokemon.is_shiny === 'true') titlePrefix += 'Shiny ';
        if (pokemon.status && pokemon.status !== 'Không' && pokemon.status !== '无') titlePrefix += `${pokemon.status} `;

        const page = document.createElement('div');
        page.id = uniqueId;
        page.className = 'rotom-page pokemon-details';

        const movesHTML = pokemon.moves.split(',').map(moveStr => {
            const parts = moveStr.split(':'); // Định dạng: Tên:Thuộc tính:Phân loại
            if (parts.length < 3) return `<div class="move-display"><span>${moveStr}</span></div>`;
            const [name, type, category] = parts;
            // Map Vietnamese category to English for icon
            const categoryMap = {'vật lý': 'physical', 'đặc biệt': 'special', 'biến hóa': 'status', '物理': 'physical', '特殊': 'special', '变化': 'status'};
            const categoryKey = category.toLowerCase();
            const categoryIconName = categoryMap[categoryKey] || 'status';

            const typeIcon = `https://raw.githubusercontent.com/msikma/pokesprite/master/misc/types/gen8/${type.toLowerCase()}.png`;
            const categoryIcon = `https://raw.githubusercontent.com/msikma/pokesprite/master/misc/seals/gen8/move-${categoryIconName}.png`;
            return `<div class="move-display">
                        <img src="${typeIcon}" class="type-icon" title="${type}">
                        <img src="${categoryIcon}" class="move-icon" title="${category}">
                        <span>${name}</span>
                    </div>`;
        }).join('');

        page.innerHTML = `
            <div class="pokemon-sprite-container">
                <img src="${getPokemonImageUrl(pokemon)}" class="main-sprite">
                <div class="status-icons">${getStatusIcons(pokemon)}</div>
            </div>
            <div class="page-title">${titlePrefix}${displayName} <span>(Lv.${pokemon.level})</span></div>
            <div class="tabs"><button class="tab-button active" data-tab="info">Thông tin cơ bản</button><button class="tab-button" data-tab="stats">Năng lực</button><button class="tab-button" data-tab="potential">Tiềm năng</button></div>
            <div id="tab-info-${pokemonKey}" class="tab-content active">
                <div class="pokemon-info-grid">
                    <div><strong>Chủng loại:</strong> ${pokemon.name}</div>
                    <div><strong>Giới tính:</strong> ${pokemon.gender}</div>
                    <div><strong>Hệ:</strong> ${pokemon.types}</div>
                    <div><strong>Đặc tính:</strong> ${pokemon.ability}</div>
                    <div><strong>Tính cách:</strong> ${pokemon.nature}</div>
                    <div><strong>Thân mật:</strong> ${pokemon.friendship}</div>
                    <div><strong>Vật phẩm:</strong> <img src="${getItemImageUrl({english_name: pokemon.held_item_en})}" class="item-icon">${pokemon.held_item}</div>
                    <div style="grid-column: 1 / -1;"><strong>EXP:</strong> ${pokemon.exp || 'N/A'}<div class="exp-bar-bg"><div class="exp-bar-fg" style="width: ${expPercent}%;"></div></div></div>
                    <div style="grid-column: 1 / -1;"><strong>Kỹ năng:</strong><div class="moves-list">${movesHTML}</div></div>
                </div>
            </div>
            <div id="tab-stats-${pokemonKey}" class="tab-content"><div class="pokemon-stats-grid"><div><strong>HP:</strong> ${pokemon.hp.split('/')[1]}</div>${pokemon.stats.split(',').map(s => `<div><strong>${s.split(':')[0].toUpperCase()}:</strong> ${s.split(':')[1]}</div>`).join('')}</div></div>
            <div id="tab-potential-${pokemonKey}" class="tab-content"><p><strong>Cá thể (IVs):</strong></p><div class="pokemon-info-grid"> ${pokemon.ivs.split(',').map(s => `<div><strong>${s.split(':')[0].toUpperCase()}:</strong> ${s.split(':')[1]}</div>`).join('')}</div><p style="margin-top:10px;"><strong>Nỗ lực (EVs):</strong></p><div class="pokemon-info-grid"> ${pokemon.evs.split(',').map(s => `<div><strong>${s.split(':')[0].toUpperCase()}:</strong> ${s.split(':')[1]}</div>`).join('')}</div></div>`;

        page.appendChild(createBackButton('page-team'));
        screen.appendChild(page);
        page.querySelectorAll('.tab-button').forEach(button => {
            button.addEventListener('click', () => {
                page.querySelectorAll('.tab-button').forEach(btn => btn.classList.remove('active'));
                button.classList.add('active');
                page.querySelectorAll('.tab-content').forEach(content => content.classList.remove('active'));
                page.querySelector(`#tab-${button.dataset.tab}-${pokemonKey}`).classList.add('active');
            });
        });
