    function renderTeamPage(teamData) {
        const page = document.createElement('div');
        page.id = 'page-team';
        page.className = 'rotom-page';
        page.innerHTML = `<div class="page-title">Đội hình Hiện tại</div>`;
        const grid = document.createElement('div');
        grid.className = 'team-grid';
        Object.entries(teamData).forEach(([pokemonKey, pokemon]) => {
            if (pokemon.name && pokemon.name !== 'Không' && pokemon.name !== '无') {
                const displayName = (pokemon.nickname && pokemon.nickname !== 'Không') ? pokemon.nickname : pokemon.name;
                let titlePrefix = '';
                if (pokemon.is_shiny === 'true') titlePrefix += 'Shiny ';
                if (pokemon.status && pokemon.status !== 'Không' && pokemon.status !== '无' && pokemon.status.toLowerCase() !== 'normal' ) titlePrefix += `${pokemon.status} `;

                const memberDiv = document.createElement('div');
                memberDiv.className = 'team-member';
                memberDiv.innerHTML = `<img src="${getPokemonImageUrl(pokemon)}" class="pokemon-icon"> <span>${titlePrefix}${displayName} (Lv.${pokemon.level})</span>`;
