    function renderShopPage(shopData, pp) { renderGenericListPage('page-shop', `Sàn giao dịch Khai phá <span class="currency">${pp || 0} PP</span>`, shopData || {}, item => { const li = document.createElement('li'); li.className = 'generic-list-item'; li.innerHTML = `<div class="generic-list-item-content"><img src="${getItemImageUrl(item)}" class="item-icon"><strong>${item.name}</strong></div><div class="item-actions"><span class="item-cost">${item.cost} PP</span><button class="item-button">Mua</button></div>`; const buyButton = li.querySelector('.item-button'); buyButton.onclick = async () => { if ((parseInt(pp, 10) || 0) < (parseInt(item.cost, 10) || 0)) { showError(`Bíp bíp! Không đủ điểm! (Cần ${item.cost} PP)`); return; } buyButton.disabled = true; buyButton.textContent = 'Đang gửi...'; const success = await sendGameActionRequest(`/send Đã dùng ${item.cost}PP mua ${item.name}`); buyButton.textContent = success ? 'Đã gửi ✓' : 'Gửi thủ công'; if (success) { setTimeout(() => { buyButton.textContent = 'Mua'; buyButton.disabled = false; }, 2500); } }; return li; }); }
    function renderTitlesPage(titlesData, currentTitle) { renderGenericListPage('page-titles', 'Danh hiệu Sở hữu', titlesData || {}, item => { const li = document.createElement('li'); const isEquipped = item.name === currentTitle; li.className = 'generic-list-item'; li.innerHTML = `<div class="generic-list-item-content"><div><strong>${item.name} ${isEquipped ? `<span style=\"color: var(--accent-red);\'>(Đã trang bị)</span>` : ''}</strong><small style="display: block; opacity: 0.8;">${item.effect}</small></div></div><div class="item-actions">${!isEquipped ? '<button class="equip-button">Trang bị</button>' : ''}</div>`; if (!isEquipped) { const equipButton = li.querySelector('.equip-button'); equipButton.onclick = async () => { equipButton.disabled = true; equipButton.textContent = 'Đang gửi...'; const success = await sendGameActionRequest(`/send Chuyển danh hiệu thành ${item.name}`); equipButton.textContent = success ? 'Đã gửi ✓' : 'Gửi thủ công'; }; } return li; }); }
    function renderBreedingPage(data) { const page = document.createElement('div'); page.id = 'page-breeding'; page.className = 'rotom-page'; let content = (data && (data.status === 'Đang tiến hành' || data.status === 'Đã hoàn thành')) ? `<h3>Trạng thái: ${data.status}</h3><div class="generic-list-item">Pokémon A: ${data.pokemon_A}</div><div class="generic-list-item">Pokémon B: ${data.pokemon_B}</div>` : `<div class="generic-list-item">Không có Pokémon trong nhà nuôi.</div>`; page.innerHTML = `<div class="page-title">Hộp Phối giống</div>${content}`; page.appendChild(createBackButton('page-main')); screen.appendChild(page); }

    // Render ban đầu
    const rawData = dataContainer.textContent.trim();
    if (rawData) {
        try {
            const data = parseRotomData(rawData);
            screen.innerHTML = '';
            renderMainPage(data);
            renderGenericListPage('page-nearby', 'Pokémon Gần đây', data.nearby_pokemon, item => { const li = document.createElement('li'); li.className = 'generic-list-item'; li.innerHTML = `<div class="generic-list-item-content"><img src="${getPokemonImageUrl(item)}" class="pokemon-icon"><span><strong>${item.name}</strong></span></div><span>${item.count}</span>`; return li; });
            renderGenericListPage('page-box', 'Hộp Pokémon', data.pokemon_box, item => { const li = document.createElement('li'); li.className = 'generic-list-item'; li.innerHTML = `<div class="generic-list-item-content"><img src="${getPokemonImageUrl(item)}" class="pokemon-icon"><span><strong>${item.name}</strong></span></div><span>Lv.${item.level}</span>`; return li; });
            renderTeamPage(data.current_team || {});
            renderShopPage(data.system_shop, (data.trainer_info || {}).pioneer_points);
            renderTitlesPage(data.unlocked_titles, (data.trainer_info || {}).current_title);
            renderGenericListPage('page-bag', 'Ba lô', data.bag, item => { const li = document.createElement('li'); li.className = 'generic-list-item'; li.innerHTML = `<div class="generic-list-item-content"><img src="${getItemImageUrl(item)}" class="item-icon"><span><strong>${item.name}</strong></span></div><span>x${item.count}</span>`; return li; });
            renderGenericListPage('page-achievements', `Thành tựu Đã mở (${(data.trainer_info || {}).achievement_points || 0} AP)`, data.unlocked_achievements, item => { const li = document.createElement('li'); li.className = 'generic-list-item'; li.innerHTML = `<div class="generic-list-item-content"><div><strong>${item.name}</strong><small style="display:block; opacity:0.8;">${item.desc}</small></div></div>`; return li; });
