            const mainPage = document.createElement('div'); mainPage.id = 'page-main'; mainPage.className = 'rotom-page active'; mainPage.innerHTML = screen.innerHTML; screen.innerHTML = ''; screen.appendChild(mainPage);
        }
    } else {
        screen.innerHTML = '<p>Truyền tải dữ liệu Rotom bị gián đoạn... Bíp bíp...</p>';
