  .hp-high { background-color: var(--day-hp-high); } .hp-mid { background-color: var(--day-hp-mid); } .hp-low { background-color: var(--day-hp-low); }
  .theme-night .hp-high { background-color: var(--night-hp-high); } .theme-night .hp-mid { background-color: var(--night-hp-mid); } .theme-night .hp-low { background-color: var(--night-hp-low); }
  .exp-bar-bg { background-color: rgba(0, 0, 0, 0.3); border-radius: 5px; height: 8px; padding: 1px; border: 1px solid rgba(0,0,0,0.4); margin-top: 4px; }
  .exp-bar-fg { height: 100%; border-radius: 2px; transition: width 0.5s; background-color: var(--day-exp-bar); }
  .theme-night .exp-bar-fg { background-color: var(--night-exp-bar); }
  .pokemon-moves { font-size: 0.8rem; margin-top: 6px; line-height: 1.4; color: var(--day-text-secondary); }
  .theme-night .pokemon-moves { color: var(--night-text-secondary); }
  .pokemon-details { font-size: 0.8rem; margin-top: 6px; line-height: 1.5; color: var(--day-text-secondary); border-top: 1px dashed; padding-top: 4px; }
  .theme-day .pokemon-details { border-color: rgba(0,0,0,0.2); }
  .theme-night .pokemon-details { color: var(--night-text-secondary); border-color: rgba(255,255,255,0.2); }
  .pokemon-details div { display: flex; justify-content: space-between; }
  .pokemon-details strong { margin-right: 5px; }
  .egg-hatching-info { font-size: 0.9rem; margin-top: 8px; color: var(--day-text-secondary); line-height: 1.5; }
  .theme-night .egg-hatching-info { color: var(--night-text-secondary); }
  .bag-category, .box-category { margin-bottom: 10px; }
  .bag-category-title, .box-category-title { font-weight: bold; margin-bottom: 5px; border-bottom: 2px dotted; padding-bottom: 3px; }
  .theme-day .bag-category-title, .theme-day .box-category-title { border-color: var(--day-window-border); }
  .theme-night .bag-category-title, .theme-night .box-category-title { border-color: var(--night-window-border); }
  .bag-item-list, .box-pokemon-list, .relationship-list { list-style: none; padding-left: 0; margin: 0; }
  .bag-item { display: flex; align-items: center; justify-content: space-between; padding: 3px 5px; }
  .item-info { display: flex; align-items: center; }
  .item-icon { width: 24px; height: 24px; margin-right: 8px; background-size: contain; background-position: center; background-repeat: no-repeat; flex-shrink: 0; }
  .box-pokemon-entry { display: flex; align-items: center; padding: 4px 5px; }
  .box-pokemon-entry .pokemon-icon { width: 50px; height: 50px; }
  #hud-trainer { border: 4px solid; border-radius: 6px; margin-bottom: 10px; transition: background-color 0.3s, border-color 0.3s; }
  .theme-day #hud-trainer { background-color: var(--day-trainer-bg); border-color: var(--day-trainer-border); }
  .theme-night #hud-trainer { background-color: var(--night-trainer-bg); border-color: var(--night-trainer-border); }
  .trainer-info-grid { display: grid; grid-template-columns: repeat(2, 1fr); gap: 8px; padding: 8px; }
  .trainer-info-item { display: flex; justify-content: space-between; align-items: center; font-size: 0.9rem; }
  .trainer-info-item span:first-child { font-weight: bold; }
  .rotom-action-button { width: 100%; padding: 10px; font-family: var(--font-pixel); font-size: 1rem; font-weight: bold; cursor: pointer; border-radius: 4px; border: 3px solid; transition: all 0.2s; box-sizing: border-box; margin-bottom: 8px; }
  .theme-day .rotom-action-button { background-color: var(--day-header-bg); color: white; border-color: var(--day-window-border); }
  .theme-night .rotom-action-button { background-color: var(--night-header-bg); color: var(--night-text-primary); border-color: var(--night-window-border); }
  .rotom-action-button:hover:not(:disabled) { filter: brightness(1.2); }
  .rotom-action-button:active:not(:disabled) { transform: translateY(1px); filter: brightness(0.9); }
  .rotom-action-button:disabled { filter: grayscale(0.5); cursor: not-allowed; opacity: 0.7; }
  .relationship-item { display: flex; justify-content: space-between; align-items: center; padding: 4px 5px; font-size: 0.9rem; border-bottom: 1px solid; }
  .relationship-item:last-child { border-bottom: none; }
  .theme-day .relationship-item { border-color: rgba(64, 120, 136, 0.3); }
  .theme-night .relationship-item { border-color: rgba(74, 85, 104, 0.5); }
  /* --- 新增附近宝可梦样式 --- */
  .nearby-pokemon-entry { cursor: pointer; padding: 5px; border-radius: 4px; transition: background-color 0.2s; }
  .theme-day .nearby-pokemon-entry:hover { background-color: rgba(255,255,255,0.4); }
  .theme-night .nearby-pokemon-entry:hover { background-color: rgba(255,255,255,0.1); }
  .status-icon-container { display: flex; gap: 4px; align-items: center; margin-left: 5px; }
  .status-icon { width: 20px; height: 20px; }
  .nearby-pokemon-name-container { display: flex; align-items: center; }
  /* --- 新增弹窗样式 --- */
  .pm-modal-overlay { position: fixed; top: 0; left: 0; width: 100%; height: 100%; backdrop-filter: blur(4px); display: flex; justify-content: center; align-items: center; z-index: 1000; padding: 15px; box-sizing: border-box; }
  .theme-day .pm-modal-overlay { background-color: var(--day-modal-bg); }
  .theme-night .pm-modal-overlay { background-color: var(--night-modal-bg); }
  .pm-modal-content { border: 4px solid; border-radius: 6px; padding: 15px; width: 100%; max-width: 400px; max-height: 90vh; overflow-y: auto; }
  .theme-day .pm-modal-content { background-color: var(--day-modal-content-bg); border-color: var(--day-window-border); }
  .theme-night .pm-modal-content { background-color: var(--night-modal-content-bg); border-color: var(--night-window-border); }
  .pm-modal-header { font-weight: bold; font-size: 1.1rem; margin-bottom: 15px; text-align: center; }
  .pm-modal-close { position: absolute; top: 10px; right: 10px; font-size: 1.5rem; cursor: pointer; border: none; background: none; color: inherit; padding: 0 8px; }
  .hidden { display: none !important; }
  .modal-list { display: flex; flex-direction: column; gap: 8px; }

  @media (max-width: 400px) {
    .trainer-info-grid { grid-template-columns: 1fr; gap: 4px; }
    .trainer-info-item { padding: 3px 0; }
  }
</style>
