<body>
<div class="statusbar-data-source">$1</div>
<div id="pm-hud-container" class="pm-hud-container">
  <div class="hud-top-bar"><span id="theme-toggle"></span></div>
  <div id="hud-trainer" class="pm-hud-window"><div class="pm-hud-header"><span>Thông tin Huấn luyện viên</span><span class="collapse-toggle">▼</span></div><div id="trainer-content" class="pm-hud-content"><div class="trainer-info-grid"><div class="trainer-info-item"><span>Tên</span><span id="trainer-name"></span></div><div class="trainer-info-item"><span>Tiền</span><span id="trainer-money"></span></div><div class="trainer-info-item"><span>Huy hiệu</span><span id="trainer-badges"></span></div><div class="trainer-info-item"><span>Cấp độ lệnh</span><span id="trainer-command-level"></span></div><div class="trainer-info-item"><span>Danh tiếng</span><span id="trainer-renown"></span></div></div></div></div>
  <div id="hud-team" class="pm-hud-window"><div class="pm-hud-header"><span>Đội hình hiện tại</span><span class="collapse-toggle">▼</span></div><div id="team-content" class="pm-hud-content"></div></div>
  <div id="hud-nearby" class="pm-hud-window"><div class="pm-hud-header"><span>Pokémon gần đây</span><span class="collapse-toggle">▼</span></div><div id="nearby-content" class="pm-hud-content"></div></div>
  <div id="hud-rotom-phone" class="pm-hud-window"><div class="pm-hud-header"><span>Điện thoại Rotom</span><span class="collapse-toggle">▼</span></div><div class="pm-hud-content"><button id="call-rotom-btn" class="rotom-action-button">Gọi điện thoại</button></div></div>
  <div id="hud-bag" class="pm-hud-window"><div class="pm-hud-header"><span>Ba lô</span><span class="collapse-toggle">▼</span></div><div id="bag-content" class="pm-hud-content"></div></div>
  <div id="hud-box" class="pm-hud-window"><div class="pm-hud-header"><span>Hộp Pokémon</span><span class="collapse-toggle">▼</span></div><div id="box-content" class="pm-hud-content"></div></div>
  <div id="hud-relationships" class="pm-hud-window"><div class="pm-hud-header"><span>Mối quan hệ</span><span class="collapse-toggle">▼</span></div><div id="relationships-content" class="pm-hud-content"></div></div>
</div>
<div id="pm-modal-overlay" class="pm-modal-overlay hidden">
    <div id="pm-modal-content" class="pm-modal-content"></div>
</div>
<script>
document.addEventListener('DOMContentLoaded', () => {
    // --- 数据与元素定义 ---
    // [TRANSLATION NOTE] Updated keys to Vietnamese to match potential output
    const STATUS_ICONS = {
        'Shiny': 'https://raw.githubusercontent.com/msikma/pokesprite/master/misc/special-attribute/shiny-stars.png',
        'Lấp lánh': 'https://raw.githubusercontent.com/msikma/pokesprite/master/misc/special-attribute/shiny-stars.png',
        'Alpha': 'https://raw.githubusercontent.com/msikma/pokesprite/master/misc/special-attribute/alpha-icon.png',
        'Thủ lĩnh': 'https://raw.githubusercontent.com/msikma/pokesprite/master/misc/special-attribute/alpha-icon.png',
        'Bá chủ': 'https://raw.githubusercontent.com/msikma/pokesprite/master/misc/special-attribute/alpha-icon.png', // 使用相同图标
        'Cực đại hóa': 'https://raw.githubusercontent.com/msikma/pokesprite/master/misc/special-attribute/gigantamax-icon.png',
        'Gigantamax': 'https://raw.githubusercontent.com/msikma/pokesprite/master/misc/special-attribute/gigantamax-icon.png',
        'Thái tinh hóa': 'https://raw.githubusercontent.com/sora-64/DS-Pokemon-Editor/main/Resources/terastal.png',
        'Terastal': 'https://raw.githubusercontent.com/sora-64/DS-Pokemon-Editor/main/Resources/terastal.png'
    };
    const dataSource = document.querySelector('.statusbar-data-source');
    const container = document.getElementById('pm-hud-container');
    const teamContent = document.getElementById('team-content');
    const bagContent = document.getElementById('bag-content');
    const boxContent = document.getElementById('box-content');
    const relationshipsContent = document.getElementById('relationships-content');
    const nearbyContent = document.getElementById('nearby-content');
    const modalOverlay = document.getElementById('pm-modal-overlay');
    const modalContent = document.getElementById('pm-modal-content');
    if (!dataSource || !dataSource.textContent.trim()) return;

    // --- 核心功能函数 ---
    function showError(message) { /* ... (函数体无变化) ... */ console.error(`Status Bar Action Error: ${message}`); const errorEl = document.createElement('div'); errorEl.textContent = message; errorEl.style.cssText = `background-color: var(--day-hp-low); color: white; padding: 8px; margin: 0 0 10px 0; border-radius: 4px; text-align: center; font-size: 0.9rem;`; const hudContainer = document.getElementById('pm-hud-container'); if (hudContainer) { hudContainer.insertBefore(errorEl, hudContainer.firstChild.nextSibling); setTimeout(() => { if(errorEl.parentElement) errorEl.parentElement.removeChild(errorEl); }, 4000); } }
    async function sendGameActionRequest(message) { /* ... (函数体无变化) ... */ try { if (window.SillyTavernAPI && window.SillyTavernAPI.sendMessage) { await window.SillyTavernAPI.sendMessage(message); return true; } if (window.extensionAPI && window.extensionAPI.sendMessage) { await window.extensionAPI.sendMessage(message); return true; } let textarea = null, sendButton = null; const textareaSelectors = ['#send_textarea', 'textarea[name="send_textarea"]', '#chat-input', 'textarea.chat-input', '#user-input', 'textarea#send_textarea', 'textarea']; const buttonSelectors = ['#send_but', 'button#send_but', 'input[type="submit"]', '.send_button', 'button[type="submit"]']; if (window.parent !== window) { for (const selector of textareaSelectors) try { textarea = window.parent.document.querySelector(selector); if (textarea) break; } catch (e) {} for (const selector of buttonSelectors) try { sendButton = window.parent.document.querySelector(selector); if (sendButton) break; } catch (e) {} } if (textarea && sendButton) { textarea.value = message; textarea.dispatchEvent(new Event('input', { bubbles: true })); sendButton.click(); return true; } if (window.parent !== window) { window.parent.postMessage({ type: 'send_message', message: message }, '*'); return true; } try { await navigator.clipboard.writeText(message); showError("Gửi tự động thất bại, tin nhắn đã được sao chép vào clipboard, vui lòng dán thủ công."); return false; } catch (clipboardError) { const tempTextarea = document.createElement('textarea'); tempTextarea.value = message; tempTextarea.style.cssText = 'position:fixed;top:50%;left:50%;transform:translate(-50%,-50%);z-index:10000;padding:10px;border:2px solid var(--day-hp-low);background-color:var(--day-window-bg);color:var(--day-text-primary);width:80%;max-width:500px;height:100px; font-family: var(--font-pixel);'; document.body.appendChild(tempTextarea); tempTextarea.select(); showError("Gửi tự động thất bại, vui lòng sao chép thủ công nội dung trong hộp văn bản phía trên và gửi."); setTimeout(() => document.body.removeChild(tempTextarea), 5000); return false; } } catch (error) { showError(`Gửi thất bại: ${error.message}`); return false; } }
    function parseSource(text) { /* ... (函数体无变化) ... */ const data = {}; const blockRegex = /\[([^\]]+)\]([\s\S]*?)\[\/\1\]/g; let match; while ((match = blockRegex.exec(text)) !== null) { const blockName = match[1]; const blockContent = match[2].trim(); const items = {}; blockContent.split('\n').forEach(line => { const parts = line.split(':'); if (parts.length >= 2) { const key = parts[0].trim(); const value = parts.slice(1).join(':').trim(); items[key] = value; } }); data[blockName] = items; } return data; }

    function structureData(parsed) {
        const structured = { team: [], bag: {}, boxes: {}, trainer: {}, relationships: {}, nearby: [] };
        // [TRANSLATION NOTE] Changed keys to expect Vietnamese input
        structured.trainer = { 
            name: parsed['Thông tin Huấn luyện viên']?.['Tên'] || parsed['训练家信息']?.['名字'] || 'Vô danh', 
            money: parsed['Thông tin Huấn luyện viên']?.['Tiền'] || parsed['训练家信息']?.['金钱'] || '0', 
            badges: parsed['Thông tin Huấn luyện viên']?.['Huy hiệu'] || parsed['训练家信息']?.['徽章'] || '0', 
            commandLevel: parsed['Thông tin Huấn luyện viên']?.['Cấp độ lệnh'] || parsed['训练家信息']?.['可命令等级'] || '0', 
            renown: parsed['Thông tin Huấn luyện viên']?.['Danh tiếng'] || parsed['训练家信息']?.['声望'] || 'N/A' 
        };
        const teamData = parsed['Trạng thái đội hình'] || parsed['队伍状态'] || {}; 
        for (let i = 1; i <= 6; i++) { 
            // Support both VN (Đội) and CN (队伍) keys for compatibility
            const prefixVN = `Đội${i}_`;
            const prefixCN = `队伍${i}_`;
            const getName = (key) => teamData[prefixVN + key] || teamData[prefixCN + key];

            if (getName('Tên') || getName('名字')) { 
                const name = getName('Tên') || getName('名字');
                if (name && name !== 'Trống' && name !== '空') {
                    structured.team.push({ 
                        name: name, 
                        level: getName('Cấp độ') || getName('等级'), 
                        hp: getName('HP'), 
                        exp: getName('EXP') || getName('经验'), 
                        moves: getName('Kỹ năng') || getName('技能'), 
                        type1: (getName('Hệ 1') || getName('属性1') || 'Thường').replace(/ /g, '_'), 
                        type2: (getName('Hệ 2') || getName('属性2') || 'Không').replace(/ /g, '_'), 
                        icon: getName('Icon') || getName('图标'), 
                        isShiny: (getName('Shiny') || getName('是否闪光')) === 'Có' || (getName('Shiny') || getName('是否闪光')) === '是', 
                        hatchTime: getName('Ấp nở') || getName('孵化剩余'), 
                        nature: getName('Tính cách') || getName('性格'), 
                        ability: getName('Đặc tính') || getName('特性'), 
                        heldItem: getName('Vật phẩm') || getName('携带道具'), 
                        friendship: getName('Thân mật') || getName('亲密度'), 
                        gender: getName('Giới tính') || getName('性别') 
                    }); 
                }
            } 
        }

        for (const key in parsed) { 
            if (key.startsWith('Ba lô_')) structured.bag[key.replace('Ba lô_', '')] = parsed[key]; 
            else if (key.startsWith('背包_')) structured.bag[key.replace('背包_', '')] = parsed[key];
        }

        const boxData = parsed['Hộp Pokémon'] || parsed['宝可梦盒子'] || {}; 
        for (const key in boxData) { 
            // Regex for VN: Hộp1_Pokémon2_Thuộc tính
            const matchVN = key.match(/Hộp(\d+)_Pokémon(\d+)_(.+)/);
            const matchCN = key.match(/盒子(\d+)_宝可梦(\d+)_(.+)/);
            const match = matchVN || matchCN;

            if (match) { 
                const [, boxNum, pkmnNum, prop] = match; 
                if (!structured.boxes[boxNum]) structured.boxes[boxNum] = {}; 
                if (!structured.boxes[boxNum][pkmnNum]) structured.boxes[boxNum][pkmnNum] = {}; 

                // Map CN props to standard VN keys if necessary, or just store
                let stdProp = prop;
                if(prop === '名字') stdProp = 'Tên';
                else if(prop === '等级') stdProp = 'Cấp độ';
                else if(prop === '属性1') stdProp = 'Hệ 1';
                else if(prop === '属性2') stdProp = 'Hệ 2';
                else if(prop === '图标') stdProp = 'Icon';
                else if(prop === '是否闪光') stdProp = 'Shiny';

                structured.boxes[boxNum][pkmnNum][stdProp] = boxData[key]; 
            } 
        }
        structured.relationships = parsed['Mối quan hệ'] || parsed['人际关系'] || {};
        const nearbyData = parsed['Pokémon gần đây'] || parsed['附近宝可梦'] || {};
        const nearbyPkmn = {};
        for (const key in nearbyData) {
            // VN: Gần_đây1_Tên
            const matchVN = key.match(/Gần_đây(\d+)_(.+)/);
            const matchCN = key.match(/附近(\d+)_(.+)/);
            const match = matchVN || matchCN;

            if (match) {
                const [, index, prop] = match;
                if (!nearbyPkmn[index]) nearbyPkmn[index] = {};

                let stdProp = prop;
                if(prop === '名字') stdProp = 'Tên';
                else if(prop === '内容') stdProp = 'Nội dung';
                else if(prop === '数量') stdProp = 'Số lượng';
                else if(prop === '状态') stdProp = 'Trạng thái';
                else if(prop === '图标') stdProp = 'Icon';

                nearbyPkmn[index][stdProp] = nearbyData[key];
            }
        }
        structured.nearby = Object.values(nearbyPkmn);
        structured.config = parsed['config'] || { theme: 'day' };
        return structured;
    }

    // --- 弹窗管理 ---
    function openModal(htmlContent) { modalContent.innerHTML = htmlContent; modalOverlay.classList.remove('hidden'); }
    function closeModal() { modalOverlay.classList.add('hidden'); modalContent.innerHTML = ''; }
    modalOverlay.addEventListener('click', (e) => { if (e.target === modalOverlay) closeModal(); });

    const rawData = parseSource(dataSource.textContent);
    const data = structureData(rawData);

    // --- UI 渲染 ---
    function renderTrainerInfo() { /* ... (渲染训练家信息，无变化) ... */ document.getElementById('trainer-name').textContent = data.trainer.name; document.getElementById('trainer-money').textContent = '₽' + data.trainer.money; document.getElementById('trainer-badges').textContent = data.trainer.badges; document.getElementById('trainer-command-level').textContent = data.trainer.commandLevel; document.getElementById('trainer-renown').textContent = data.trainer.renown; }
    function renderTeam() { 
        teamContent.innerHTML = data.team.length > 0 ? data.team.map(p => { 
            if (p.name === 'Trứng' || p.name === '蛋') { 
                const iconUrl = 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/items/mystery-egg.png'; 
                const iconStyle = `style="background-image: url('${iconUrl}');"`; 
                const hatchInfo = p.hatchTime ? `Thời gian nở còn lại: ${p.hatchTime}` : 'Sắp nở...'; 
                return `<div class="pokemon-entry"><div class="pokemon-icon" ${iconStyle}></div><div class="pokemon-info"><div class="pokemon-name-level"><span>Trứng</span></div><div class="egg-hatching-info"><div>Đang ấp trứng...</div><div>${hatchInfo}</div></div></div></div>`; 
            } else { 
                const [currentHP, maxHP] = (p.hp || '0/0').split('/').map(Number); 
                const hpPercent = maxHP > 0 ? (currentHP / maxHP) * 100 : 0; 
                let hpClass = hpPercent < 20 ? 'hp-low' : hpPercent < 50 ? 'hp-mid' : 'hp-high'; 
                const [currentEXP, totalEXP] = (p.exp || '0/100').split('/').map(Number); 
                const expPercent = totalEXP > 0 ? (currentEXP / totalEXP) * 100 : 0; 
                let genderHTML = ''; 
                if (p.gender === '♂') genderHTML = ` <span class="gender-male">♂</span>`; 
                else if (p.gender === '♀') genderHTML = ` <span class="gender-female">♀</span>`; 

                // Use translated type variables
                let typesHTML = (p.type1 && p.type1 !== 'Không' && p.type1 !== '无' ? `<span class="type-badge" style="background-color: var(--type-${p.type1});">${p.type1}</span>` : '') + 
                                (p.type2 && p.type2 !== 'Không' && p.type2 !== '无' ? `<span class="type-badge" style="background-color: var(--type-${p.type2});">${p.type2}</span>` : ''); 

                let movesHTML = p.moves ? `<div class="pokemon-moves"><strong>Kỹ năng:</strong> ${p.moves.replace(/,/g, ' / ')}</div>` : ''; 
                let detailsHTML = [
                    (p.nature ? `<div><strong>Tính cách:</strong> <span>${p.nature}</span></div>` : ''), 
                    (p.ability ? `<div><strong>Đặc tính:</strong> <span>${p.ability}</span></div>` : ''), 
                    (p.heldItem && p.heldItem !== 'Không' && p.heldItem !== '无' ? `<div><strong>Vật phẩm:</strong> <span>${p.heldItem}</span></div>` : ''), 
                    (p.friendship ? `<div><strong>Thân mật:</strong> <span>${p.friendship}</span></div>` : '')
                ].filter(Boolean).join(''); 

                if(detailsHTML) { detailsHTML = `<div class="pokemon-details">${detailsHTML}</div>`; } 
                let iconStyle = ''; 
                if (p.icon) { 
                    const baseUrl = p.isShiny ? 'https://play.pokemonshowdown.com/sprites/ani-shiny/' : 'https://play.pokemonshowdown.com/sprites/ani/'; 
                    const iconUrl = baseUrl + p.icon; 
                    iconStyle = `style="background-image: url('${iconUrl}');"`; 
                } 
                return `<div class="pokemon-entry"><div class="pokemon-icon" ${iconStyle}></div><div class="pokemon-info"><div class="pokemon-name-level"><span>${p.name}${genderHTML}</span><span>Lv.${p.level}</span></div><div class="hp-bar-bg"><div class="hp-bar-fg ${hpClass}" style="width: ${hpPercent}%;"></div></div><div class="exp-bar-bg"><div class="exp-bar-fg" style="width: ${expPercent}%;"></div></div><div class="pokemon-types">${typesHTML}</div>${movesHTML}${detailsHTML}</div></div>`; 
            } 
        }).join('') : '<div>Không có Pokémon nào trong đội.</div>'; 
    }

    function renderBag() { 
        const bagHTML = Object.entries(data.bag).map(([cat, items]) => { 
            if (Object.keys(items).length === 0) return ''; 
            return `<div class="bag-category"><div class="bag-category-title">${cat}</div><ul class="bag-item-list">${Object.entries(items).map(([name, value]) => { 
                const parts = String(value).split(','); 
                const count = parts[0].trim(); 
                const iconFile = parts.length > 1 ? parts[1].trim() : null; 
                let iconHTML = '<div class="item-icon"></div>'; 
                if (iconFile) { 
                    const iconUrl = `https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/items/${iconFile}`; 
                    iconHTML = `<div class="item-icon" style="background-image: url('${iconUrl}')"></div>`; 
                } 
                return `<li class="bag-item"><div class="item-info">${iconHTML}<span>${name}</span></div><span>x${count}</span></li>`; 
            }).join('')}</ul></div>`; 
        }).join(''); 
        bagContent.innerHTML = bagHTML.trim() ? bagHTML : '<div>Ba lô trống rỗng.</div>'; 
    }

    function renderBox() { 
        const boxHTML = Object.entries(data.boxes).map(([boxNum, pokemons]) => `<div class="box-category"><div class="box-category-title">Hộp ${boxNum}</div><ul class="box-pokemon-list">${Object.values(pokemons).map(p => { 
            // Normalize property access for rendering
            const type1 = (p['Hệ 1'] || p['属性1'] || 'Thường').replace(/ /g, '_');
            const type2 = (p['Hệ 2'] || p['属性2'] || 'Không').replace(/ /g, '_');
            const name = p['Tên'] || p['名字'];
            const level = p['Cấp độ'] || p['等级'];
            const icon = p['Icon'] || p['图标'];
            const isShiny = (p['Shiny'] || p['是否闪光']) === 'Có' || (p['Shiny'] || p['是否闪光']) === '是';

            let typesHTML = (type1 && type1 !== 'Không' && type1 !== '无' ? `<span class="type-badge" style="background-color: var(--type-${type1});">${type1}</span>` : '') + 
                            (type2 && type2 !== 'Không' && type2 !== '无' ? `<span class="type-badge" style="background-color: var(--type-${type2});">${type2}</span>` : ''); 

            let iconStyle = ''; 
            if (name === 'Trứng' || name === '蛋') { 
                const iconUrl = 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/items/mystery-egg.png'; 
                iconStyle = `style="background-image: url('${iconUrl}');"`; 
            } else if (icon) { 
                const baseUrl = isShiny ? 'https://play.pokemonshowdown.com/sprites/ani-shiny/' : 'https://play.pokemonshowdown.com/sprites/ani/'; 
                const iconUrl = baseUrl + icon; 
                iconStyle = `style="background-image: url('${iconUrl}');"`; 
            } 
            return `<li class="box-pokemon-entry"><div class="pokemon-icon" ${iconStyle}></div><div class="pokemon-info"><div class="pokemon-name-level"><span>${name}</span><span>Lv.${level}</span></div><div class="pokemon-types">${typesHTML}</div></div></li>`; 
        }).join('')}</ul></div>`).join(''); 
        boxContent.innerHTML = boxHTML.trim() ? boxHTML : '<div>Không có Pokémon nào trong máy tính.</div>'; 
    }

    function renderRelationships() { 
        const relationshipsHTML = Object.entries(data.relationships).map(([name, level]) => `<li class="relationship-item"><span>${name}</span><span>${level}</span></li>`).join(''); 
        relationshipsContent.innerHTML = relationshipsHTML ? `<ul class="relationship-list">${relationshipsHTML}</ul>` : '<div>Chưa có thông tin mối quan hệ.</div>'; 
    }

    function renderNearby() {
        if (!nearbyContent) return;
        nearbyContent.innerHTML = data.nearby.length > 0 ? data.nearby.map((p, index) => {
            const name = p['Tên'] || p['名字'] || 'Không xác định';
            const content = p['Nội dung'] || p['内容'];
            const quantity = p['Số lượng'] || p['数量'] || 1;
            const status = p['Trạng thái'] || p['状态'] || 'Thường'; // Default to VN 'Thường' or keep check strict
            const iconFile = p['Icon'] || p['图标'];

            const displayName = content ? `${name} (${content})` : name;

            let iconUrl = 'https://play.pokemonshowdown.com/sprites/ani/unown.gif';
            if (iconFile) {
                const isShiny = status === 'Shiny' || status === '闪光';
                const baseUrl = isShiny ? 'https://play.pokemonshowdown.com/sprites/ani-shiny/' : 'https://play.pokemonshowdown.com/sprites/ani/';
                iconUrl = baseUrl + iconFile;
            }
            let statusIconsHTML = '';
            // Check for both VN and CN status keys just in case
            if (status !== 'Thường' && status !== '普通') {
                const statusIconUrl = STATUS_ICONS[status];
                if(statusIconUrl) statusIconsHTML += `<img src="${statusIconUrl}" class="status-icon" title="${status}">`;
            }
            return `<div class="nearby-pokemon-entry" data-index="${index}">
                      <div class="pokemon-icon" style="background-image: url('${iconUrl}');"></div>
                      <div class="pokemon-info">
                        <div class="nearby-pokemon-name">
                          <div class="nearby-pokemon-name-container"><span>${displayName}</span><div class="status-icon-container">${statusIconsHTML}</div></div>
                          <span>x${quantity}</span>
                        </div>
                      </div>
                    </div>`;
        }).join('') : '<div>Không phát hiện Pokémon đặc biệt nào gần đây.</div>';
    }

    // --- 交互逻辑 ---
    // [!] 修改 showActionModal 函数
    function showActionModal(pkmn) {
        const name = pkmn['Tên'] || pkmn['名字'] || 'Pokémon';
        const contentName = pkmn['Nội dung'] || pkmn['内容'] || name;
        const quantity = parseInt(pkmn['Số lượng'] || pkmn['数量'] || 1, 10);
        const status = pkmn['Trạng thái'] || pkmn['状态'] || 'Thường';

        // Update condition for VN/CN
        const isRaid = status === 'Cực đại hóa' || status === '极巨化' || status === 'Thái tinh hóa' || status === '太晶化';

        // [!] 新增：生成带状态的全名，用于发送消息
        const fullNameWithStatus = (status !== 'Thường' && status !== '普通' && !isRaid) ? `${status} ${contentName}` : contentName;

        const isSingleNormalShiny = quantity === 1 && (status === 'Thường' || status === '普通' || status === 'Shiny' || status === '闪光');

        let buttonsHTML = `
            <button class="rotom-action-button" id="battle-btn" ${isRaid ? 'disabled' : ''}>Chiến đấu</button>
            <button class="rotom-action-button" id="catch-btn" ${!isSingleNormalShiny ? 'disabled' : ''}>Bắt ngay</button>
            <button class="rotom-action-button" id="raid-btn" ${isRaid ? '' : 'disabled'}>Mở Raid Battle</button>
        `;

        let modalHTML = `<div class="pm-modal-header">Thao tác: ${contentName}</div><div class="modal-list">${buttonsHTML}</div><button class="pm-modal-close" onclick="document.getElementById('pm-modal-overlay').classList.add('hidden')">×</button>`;
        openModal(modalHTML);

        const battleBtn = document.getElementById('battle-btn');
        if (battleBtn && !battleBtn.disabled) {
            battleBtn.addEventListener('click', async () => {
                // [!] 使用 fullNameWithStatus
                await sendGameActionRequest(`Chiến đấu với ${quantity} con ${fullNameWithStatus}!`);
                closeModal();
            });
        }

        const catchBtn = document.getElementById('catch-btn');
        if (catchBtn && !catchBtn.disabled) {
            catchBtn.addEventListener('click', () => showPokeballModal(pkmn));
        }

        const raidBtn = document.getElementById('raid-btn');
        if (raidBtn && !raidBtn.disabled) {
            raidBtn.addEventListener('click', () => showTeamSelectModal(pkmn));
        }
    }

    // [!] 修改 showPokeballModal 函数
    function showPokeballModal(pkmn) {
        const pokeballs = data.bag['Poké Ball'] || data.bag['精灵球'] || {};
        let buttonsHTML = Object.entries(pokeballs).map(([name, value]) => {
            const count = String(value).split(',')[0].trim();
            return `<button class="rotom-action-button" data-ball-name="${name}">${name} (x${count})</button>`;
        }).join('');
        if (!buttonsHTML) buttonsHTML = '<div>Không có Poké Ball trong ba lô.</div>';

        let modalHTML = `<div class="pm-modal-header">Chọn Poké Ball</div><div class="modal-list">${buttonsHTML}</div><button class="pm-modal-close" onclick="document.getElementById('pm-modal-overlay').classList.add('hidden')">×</button>`;
        openModal(modalHTML);

        // [!] 新增：生成带状态的全名，用于发送消息
        const status = pkmn['Trạng thái'] || pkmn['状态'] || 'Thường';
        const name = pkmn['Tên'] || pkmn['名字'] || 'Pokémon';
        const fullNameWithStatus = (status !== 'Thường' && status !== '普通') ? `${status} ${name}` : name;

        document.querySelectorAll('[data-ball-name]').forEach(button => {
            button.addEventListener('click', async (e) => {
                const ballName = e.currentTarget.dataset.ballName;
                // [!] 使用 fullNameWithStatus
                await sendGameActionRequest(`Đã sử dụng ${ballName} lên ${fullNameWithStatus}`);
                closeModal();
            });
        });
    }

    function showTeamSelectModal(pkmn) {
        const team = data.team.filter(p => p.name !== 'Trứng' && p.name !== '蛋' && (p.hp || '0/0').split('/')[0] > 0);
        let buttonsHTML = team.map(member => {
            return `<button class="rotom-action-button" data-member-name="${member.name}">Lên đi! ${member.name} (Lv.${member.level})</button>`;
        }).join('');
        if (!buttonsHTML) buttonsHTML = '<div>Trong đội không có Pokémon nào có thể chiến đấu.</div>';

        const status = pkmn['Trạng thái'] || pkmn['状态'];
        const content = pkmn['Nội dung'] || pkmn['内容'];
        const raidType = (status === 'Cực đại hóa' || status === '极巨化') ? 'Max Raid Battle' : 'Tera Raid Battle';
        let modalHTML = `<div class="pm-modal-header">Chọn Pokémon ra trận</div><div class="modal-list">${buttonsHTML}</div><button class="pm-modal-close" onclick="document.getElementById('pm-modal-overlay').classList.add('hidden')">×</button>`;
        openModal(modalHTML);

        document.querySelectorAll('[data-member-name]').forEach(button => {
            button.addEventListener('click', async (e) => {
                const memberName = e.currentTarget.dataset.memberName;
                await sendGameActionRequest(`Lên đi! ${memberName}! Cùng 3 đồng đội bất ngờ xuất hiện mở cuộc ${raidType} đối với ${content}!`);
                closeModal();
            });
        });
    }

    // --- 初始化与事件绑定 ---
    function applyTheme(theme) { container.className = 'pm-hud-container'; container.classList.add(theme === 'night' ? 'theme-night' : 'theme-day'); const themeToggle = document.getElementById('theme-toggle'); if (themeToggle) { themeToggle.textContent = theme === 'night' ? '☀️' : '🌙'; } try { localStorage.setItem('pmHudTheme', theme); } catch (e) {} }
    let initialTheme = 'day'; try { initialTheme = localStorage.getItem('pmHudTheme') || data.config.theme || 'day'; } catch (e) { initialTheme = data.config.theme || 'day'; }
    applyTheme(initialTheme);

    document.getElementById('theme-toggle').addEventListener('click', (e) => { e.stopPropagation(); const newTheme = container.classList.contains('theme-night') ? 'day' : 'night'; applyTheme(newTheme); });

    ['hud-trainer', 'hud-team', 'hud-rotom-phone', 'hud-bag', 'hud-box', 'hud-relationships', 'hud-nearby'].forEach(id => { const w = document.getElementById(id); if (w) { const h = w.querySelector('.pm-hud-header'); try { if (localStorage.getItem(id + '-collapsed') === 'true') w.classList.add('collapsed'); } catch (e) {} if (h) h.addEventListener('click', (e) => { if (e.target.closest('#theme-toggle')) return; const i = w.classList.toggle('collapsed'); try { localStorage.setItem(id + '-collapsed', i); } catch (e) {} }); } });

    const callRotomBtn = document.getElementById('call-rotom-btn');
    if (callRotomBtn) {
        callRotomBtn.addEventListener('click', async () => {
            callRotomBtn.disabled = true; callRotomBtn.textContent = 'Đang gọi...';
            const success = await sendGameActionRequest('Gọi Điện thoại Rotom');
            if (success) { callRotomBtn.textContent = 'Kết nối thành công ✓'; } else { callRotomBtn.textContent = 'Gửi tự động thất bại'; }
            setTimeout(() => { callRotomBtn.textContent = 'Gọi điện thoại'; callRotomBtn.disabled = false; }, 2500);
        });
    }

    if (nearbyContent) {
        nearbyContent.addEventListener('click', (e) => {
            const entry = e.target.closest('.nearby-pokemon-entry');
            if (entry) {
                const index = entry.dataset.index;
                if (index !== undefined && data.nearby[index]) {
                    showActionModal(data.nearby[index]);
                }
            }
        });
    }

    renderTrainerInfo();
    renderTeam();
    renderBag();
    renderBox();
    renderRelationships();
    renderNearby();
});
</script>
</body>
</html>
